from agent import *from models.products import *XCAT = ['Nach Hersteller', 'alle anzeigen', 'Nach Größen', 'Sale', 'BLOG']def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request('https://www.beamer-discount.de/'), process_frontpage, dict())def process_frontpage(data, context, session):    strip_namespace(data)    cats1 = data.xpath('//div[@class="advanced-menu"]/div')    for cat1 in cats1:        name1 = cat1.xpath('div/a/@title').string().replace('Zur Kategorie', '').replace('Weiteres', '').strip()        url = cat1.xpath('div/a/@href').string()        if name1 not in XCAT:            cats2 = cat1.xpath('div/ul/li')            for cat2 in cats2:                name2 = cat2.xpath('a/text()').string()                url = cat2.xpath('a/@href').string()                if name2 not in XCAT:                    if 'Alle' in name2:                        name2 = ''                    cats3 = cat2.xpath('ul/li/a')                    if not cats3:                        session.queue(Request(url+'?n=74'), process_prodlist, dict(cat=name1+'|'+name2))                    for cat3 in cats3:                        name3 = cat3.xpath('.//text()').string()                        url = cat3.xpath('@href').string()                        if name3 not in XCAT:                            session.queue(Request(url+'?n=74'), process_prodlist, dict(cat=name1+'|'+name2+'|'+name3))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//div[@class="product--info"][.//span[@class="product--rating"]]/a[@class="product--title"]')    for prod in prods:        name = prod.xpath('@title').string()        url = prod.xpath('@href').string().split('?')[0]        session.queue(Request(url), process_product, dict(context, name=name, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url+'&n=74'), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat'].replace('Sonstiges Zubehör', '').replace('||', '|').strip(' |')    product.manufacturer = data.xpath('//meta[@property="product:brand"]/@content').string()    product.ssid = data.xpath('//meta[@itemprop="productID"]/@content').string()    product.sku = data.xpath('//span[@itemprop="sku"]/text()').string()    ean = data.xpath('//meta[contains(@itemprop, "gtin")]/@content').string()    if ean:        product.properties.append(ProductProperty(type='id.ean', value=ean))    revs = data.xpath('//div[@itemprop="review"]')    for rev in revs:        review = Review()        review.type = 'user'        review.url = product.url        review.date = rev.xpath('.//meta[@itemprop="datePublished"]/@content').string()        author = rev.xpath('.//span[@itemprop="author"]/text()').string()        if author:            review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath('.//meta[@itemprop="ratingValue"]/@content').string()        if grade_overall:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0, worst=0.5))        excerpt = rev.xpath('.//p[@itemprop="reviewBody"]/text()').string(multiple=True)        title = rev.xpath('.//h4[@class="content--title"]/text()').string()        if excerpt:            review.title = title        elif title:            excerpt = title        if excerpt:            review.properties.append(ReviewProperty(type="excerpt", value=excerpt))            review.ssid = review.digest() if author else review.digest(excerpt)            product.reviews.append(review)    if product.reviews:        session.emit(product)    # All revs loaded